export function generateYouTube(inputs: YouTubeInputs, seed: number = 0): YouTubeOutput {
  const v = seed % 3
  const p = inputs.problem
  const fmt = inputs.videoFormat

  const titleSet = TITLES[p] ?? TITLES['injection-molding-defects']
  const titleIdx = fmt === 'shorts' ? 0 : fmt === '60-90s' ? 1 : 2
  const titles = titleSet[titleIdx] ?? titleSet[0]
  const title = titles[v % titles.length] ?? titles[0]

  const thumbnailRaw = THUMBNAIL_TEXTS[p] ?? THUMBNAIL_TEXTS['injection-molding-defects']
  const thumbnailParts = thumbnailRaw.split('|')
  const thumbnailText = thumbnailParts[v % thumbnailParts.length] ?? thumbnailParts[0]

  const hooksArr = THREE_SECOND_HOOKS[p] ?? THREE_SECOND_HOOKS['injection-molding-defects']
  const threeSecondHook = hooksArr[v] ?? hooksArr[0]

  const openingArr = OPENING_LINES[p] ?? OPENING_LINES['injection-molding-defects']
  const openingLine = openingArr[v] ?? openingArr[0]

  const scriptArr = SCRIPT_OUTLINES[p] ?? SCRIPT_OUTLINES['injection-molding-defects']
  const scriptOrOutline = scriptArr[v] ?? scriptArr[0]

  const beatsArr = RETENTION_BEATS[p] ?? RETENTION_BEATS['injection-molding-defects']
  const retentionBeats = beatsArr

  const businessInsight = BUSINESS_INSIGHTS[p] ?? BUSINESS_INSIGHTS['injection-molding-defects']

  const ctasArr = VIDEO_CTAS[p] ?? VIDEO_CTAS['injection-molding-defects']
  const cta = ctasArr[v % ctasArr.length] ?? ctasArr[0]

  const repArr = REPURPOSING_SUGGESTIONS[p] ?? REPURPOSING_SUGGESTIONS['injection-molding-defects']

  const qualityScore = scoreContent(inputs, true, true, true, scriptOrOutline.split(' ').length)

  const improvementSuggestions = [
    'Add a specific part geometry or end market (automotive, medical, consumer) to anchor the scenario to a recognizable context for the target viewer.',
    'Include a specific resin type (PP, ABS, nylon) in the cost scenario — it grounds the material cost numbers in real production conditions.',
    'Reference the injection molding machine specification (tonnage, shot size) to give manufacturing engineers a concrete mental model for the scale of the cost scenario.',
  ]

  return {
    platform: 'youtube',
    title,
    thumbnailText,
    threeSecondHook,
    openingLine,
    scriptOrOutline,
    retentionBeats,
    businessInsight,
    cta,
    repurposingSuggestions: repArr.slice(0, 3),
    qualityScore,
    improvementSuggestions,
  }
}
